{% extends "base.html" %}
{% load static %}

{% block extra_head %}
<script src="{% static 'js/chat.js' %}" defer></script>
{% endblock %}

{% block content %}
<div class="flex flex-col h-full max-w-3xl mx-auto">
    <header class="flex items-center justify-between p-4 border-b border-gray-800">
        <h1 class="text-lg font-semibold text-gray-300">Ollama Chat</h1>
        <span class="text-xs text-gray-500" id="model-name">model: {{ ollama_model }}</span>
    </header>

    <div id="message-list" class="flex-1 overflow-y-auto p-4 space-y-4">
        {% include "chat/_empty_state.html" %}
    </div>

    {% include "chat/_input_area.html" %}
</div>

<div id="message-list-hx" style="display:none;"></div>

<span id="stream-end-marker" data-hx-swap-oob="true"></span>
{% endblock %}

(function () {
  const form = document.getElementById('chat-form');
  const input = document.getElementById('message-input');
  const sendBtn = document.getElementById('send-btn');
  const messageList = document.getElementById('message-list');

  let ws = null;
  let currentResponseDomId = null;
  let currentContentEl = null;

  function createConnection() {
    const protocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
    const wsUrl = protocol + '//' + window.location.host + '/ws/chat/';

    ws = new WebSocket(wsUrl);

    ws.onopen = function () {
      console.log('WebSocket connected');
    };

    ws.onmessage = function (event) {
      const data = JSON.parse(event.data);

      if (data.error) {
        appendError(data.error);
        resetStreamingState();
        return;
      }

      if (data.token) {
        if (!currentContentEl) {
          currentResponseDomId = 'resp-' + Date.now();
          appendAssistantBubble(currentResponseDomId, '');
          currentContentEl = document.getElementById('content-' + currentResponseDomId);
        }
        currentContentEl.textContent += data.token;
        messageList.scrollTop = messageList.scrollHeight;
      }

      if (data.done) {
        resetStreamingState();
      }
    };

    ws.onclose = function () {
      console.log('WebSocket disconnected');
      ws = null;
    };

    ws.onerror = function () {
      console.error('WebSocket error');
    };
  }

  function resetStreamingState() {
    currentResponseDomId = null;
    currentContentEl = null;
    enableInput();
  }

  function enableInput() {
    input.disabled = false;
    sendBtn.disabled = false;
    input.focus();
  }

  function disableInput() {
    input.disabled = true;
    sendBtn.disabled = true;
  }

  function clearEmptyState() {
    const empty = messageList.querySelector('.flex.items-center.justify-center');
    if (empty) {
      empty.remove();
    }
  }

  function appendUserMessage(text) {
    const domId = 'user-' + Date.now();
    const html = buildBubbleHtml(domId, 'user', 'You', 'UG', text);
    insertBubble(html);
    messageList.scrollTop = messageList.scrollHeight;
  }

  function appendAssistantBubble(domId, text) {
    const html = buildBubbleHtml(domId, 'assistant', 'Assistant', 'AI', text);
    insertBubble(html);
  }

  function appendError(text) {
    const domId = 'err-' + Date.now();
    const html =
      '<div class="flex gap-3" id="msg-' + domId + '">' +
      '<div class="flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold bg-red-800 text-red-200">!!</div>' +
      '<div class="flex-1 min-w-0">' +
      '<div class="text-xs font-medium mb-1 text-red-400">Error</div>' +
      '<div class="text-sm text-red-300">' + escapeHtml(text) + '</div>' +
      '</div></div>';
    insertBubble(html);
    messageList.scrollTop = messageList.scrollHeight;
  }

  function buildBubbleHtml(domId, role, label, initials, content) {
    var avatarBg = role === 'user' ? 'bg-emerald-700 text-emerald-100' : 'bg-gray-700 text-gray-300';
    return (
      '<div class="flex gap-3" id="msg-' + domId + '">' +
      '<div class="flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold ' + avatarBg + '">' +
      initials +
      '</div>' +
      '<div class="flex-1 min-w-0">' +
      '<div class="text-xs font-medium mb-1 text-gray-400">' + label + '</div>' +
      '<div class="prose prose-invert prose-sm max-w-none break-words" id="content-' + domId + '">' +
      escapeHtml(content) +
      '</div>' +
      '</div></div>'
    );
  }

  function insertBubble(html) {
    var el = document.createElement('div');
    el.innerHTML = html;
    while (el.firstChild) {
      messageList.appendChild(el.firstChild);
    }
  }

  function escapeHtml(text) {
    var map = {'&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#x27;'};
    return String(text).replace(/[&<>"']/g, function (c) { return map[c]; });
  }

  input.addEventListener('keydown', function (e) {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      form.dispatchEvent(new Event('submit'));
    }
  });

  input.addEventListener('input', function () {
    this.style.height = 'auto';
    this.style.height = Math.min(this.scrollHeight, 200) + 'px';
  });

  form.addEventListener('submit', function (e) {
    e.preventDefault();
    var text = input.value.trim();
    if (!text) return;
    if (!ws || ws.readyState !== WebSocket.OPEN) {
      createConnection();
      setTimeout(function () {
        if (ws && ws.readyState === WebSocket.OPEN) {
          sendMessage(text);
        } else {
          appendError('Cannot connect to server. Please try again.');
        }
      }, 300);
    } else {
      sendMessage(text);
    }
  });

  function sendMessage(text) {
    clearEmptyState();
    appendUserMessage(text);
    disableInput();
    ws.send(JSON.stringify({ message: text }));
    input.value = '';
    input.style.height = 'auto';
    messageList.scrollTop = messageList.scrollHeight;
  }

  createConnection();
})();
